The directory is empty, so I'll provide a complete implementation. Here's how to do it using ASP.NET Core's built-in `IExceptionHandler` (available in .NET 8+):

**1. Create an exception handler:**

```csharp
// ExceptionHandling/GlobalExceptionHandler.cs
using Microsoft.AspNetCore.Diagnostics;
using Microsoft.AspNetCore.Mvc;

public class GlobalExceptionHandler : IExceptionHandler
{
    private readonly ILogger<GlobalExceptionHandler> _logger;

    public GlobalExceptionHandler(ILogger<GlobalExceptionHandler> logger)
    {
        _logger = logger;
    }

    public async ValueTask<bool> TryHandleAsync(
        HttpContext httpContext,
        Exception exception,
        CancellationToken cancellationToken)
    {
        var (statusCode, title) = exception switch
        {
            KeyNotFoundException   => (StatusCodes.Status404NotFound, "Not Found"),
            ArgumentException      => (StatusCodes.Status400BadRequest, "Bad Request"),
            InvalidOperationException => (StatusCodes.Status409Conflict, "Conflict"),
            _ => (StatusCodes.Status500InternalServerError, "Internal Server Error")
        };

        _logger.LogError(exception, "Unhandled exception: {Message}", exception.Message);

        var problemDetails = new ProblemDetails
        {
            Status = statusCode,
            Title = title,
            Detail = statusCode == 500 ? "An unexpected error occurred." : exception.Message,
            Instance = httpContext.Request.Path
        };

        httpContext.Response.StatusCode = statusCode;
        await httpContext.Response.WriteAsJsonAsync(problemDetails, cancellationToken);

        return true; // exception is handled
    }
}
```

**2. Register in `Program.cs`:**

```csharp
var builder = WebApplication.CreateBuilder(args);

// Add Problem Details support
builder.Services.AddProblemDetails();

// Register the global exception handler
builder.Services.AddExceptionHandler<GlobalExceptionHandler>();

var app = builder.Build();

// Enable the exception handler middleware (must be early in the pipeline)
app.UseExceptionHandler();

// Your endpoints — no try-catch needed
app.MapGet("/items/{id}", (int id) =>
{
    if (id < 0) throw new ArgumentException("ID must be positive");
    if (id == 0) throw new KeyNotFoundException("Item not found");
    if (id == 99) throw new InvalidOperationException("Item is locked");
    return Results.Ok(new { Id = id, Name = "Example" });
});

app.Run();
```

**Key points:**

- `IExceptionHandler` is the modern .NET 8+ approach — no custom middleware class needed
- `AddProblemDetails()` ensures framework-generated errors (404 from routing, validation errors) also use RFC 7807
- 500 responses hide the real exception message to avoid leaking internals
- The handler logs the full exception server-side for debugging
- All endpoints automatically benefit without any per-endpoint `try-catch`

For **.NET 7 or earlier**, replace `IExceptionHandler` with custom middleware:

```csharp
app.UseExceptionHandler(err => err.Run(async context =>
{
    var exception = context.Features.Get<IExceptionHandlerFeature>()?.Error;
    // same mapping logic here
}));
```
